import React from "react";
import { Box, Flex } from "reflexbox";
import Fade from "react-reveal/Fade";
import Text from "../Library/Text/Text";
import Tile from "../Library/Tile/Tile";
import Hr from "../Library/Hr/Hr";

const Work = ({ experience }) => {
  return (
    <Fade bottom>
      <Box
        mt={["20%", "15%", "10%", "7%"]}
        id="work"
        ml="15%"
        style={{ zIndex: "1000" }}
      >
        <Text
          fontSize={["m", "s", "xxs", "xxs"]}
          fontWeight="l"
          textTransform="uppercase"
          letterSpacing="0.1rem"
          mb={["25%", "25%", "10%", "8%"]}
        >
          Experience
          <Hr />
        </Text>
        <Flex
          flexWrap={["", "", "wrap", "wrap"]}
          flexDirection={["column", "column", "row", "row"]}
          mx={-2}
          justifyContent="space-between"
        >
          {experience.map((work, index) => (
            <Box
              width={1 / 2}
              mt={
                index % 2 === 1
                  ? ["10%", "10%", "20%", "15%"]
                  : ["10%", "10%", "0%", "0%"]
              }
              mb={
                index % 2 === 0
                  ? ["10%", "10%", "20%", "18%"]
                  : ["10%", "10%", "0%", "0%"]
              }
              key={index}
            >
              <Fade bottom>
                <Tile work={work} key={index} type="experience" />
              </Fade>
            </Box>
          ))}
        </Flex>
      </Box>
    </Fade>
  );
};

export default Work;
