import React from "react";
import { Box } from "reflexbox";
import Text from "../Library/Text/Text";
import Link from "../Library/Link/Link";
import Hr from "../Library/Hr/Hr";

const ContactUs = () => {
  const socialMedia = [
    {
      socialMedia: "Twitter",
      icon: "fa fa-twitter-square",
      url: "https://www.twitter.com/daiviksheth",
    },
    {
      socialMedia: "Linkedin",
      icon: "fa fa-linkedin-square",
      url: "https://www.linkedin.com/in/daiviksheth",
    },
    {
      socialMedia: "E-Mail",
      icon: "fa fa-envelope",
      url: "mailto:me@daiviksheth.com?Subject=Hello!",
    },
  ];
  return (
    <Box mt={["20%", "15%", "10%", "7%"]} ml="15%" id="contact">
      <Text
        fontSize={["m", "s", "xxs", "xxs"]}
        fontWeight="l"
        textTransform="uppercase"
        letterSpacing="0.1rem"
        mb={["25%", "25%", "10%", "8%"]}
      >
        Get In Touch
        <Hr />
      </Text>
      <Text
        fontSize={["m", "s", "xxs", "xxs"]}
        fontWeight="l"
        textTransform="uppercase"
        letterSpacing="0.1rem"
        mb={["7%", "7%", "2%", "3%"]}
      >
        Business Inquiries
      </Text>
      <Text
        fontSize={["xl", "l", "s", "s"]}
        fontWeight="l"
        letterSpacing="0.1rem"
        mb={["15%", "12%", "5%", "5%"]}
        lineHeight="1rem"
      >
        me@daiviksheth.com
      </Text>
      <Text
        fontSize={["m", "s", "xxs", "xxs"]}
        mb={["5%", "5%", "2%", "3%"]}
        fontWeight="l"
        textTransform="uppercase"
        letterSpacing="0.1rem"
      >
        Connect
      </Text>
      {socialMedia.map((social, index) => (
        <Text
          marginRight={["8%", "2%", "2%", "2%"]}
          display="inline"
          fontSize={["xxl", "l", "s", "s"]}
          key={index}
        >
          <Link href={social.url}>
            <i className={social.icon}></i>
          </Link>
        </Text>
      ))}
    </Box>
  );
};

export default ContactUs;
