import React from "react";
import ReactGA from "react-ga";
import style from "../CSS/index.module.css";

const DailyDash = () => {
  const onButtonClick = () => {
    ReactGA.event({
      category: "Download",
      action: "User Clicked Download",
    });
    window.open(
      "https://chrome.google.com/webstore/detail/daily-dash/plafjgkiibeflkajbidipjiinpememgn/",
      "_blank"
    );
  };
  const onHyperlinkCliked = () => {
    ReactGA.event({
      category: "Redirect",
      action: "daiviksheth.com",
    });
    window.open("http://www.daiviksheth.com", "_blank");
  };

  return (
    <div className={`${style.appGrid} ${style.grid}`}>
      <div className={`${style.area1}`}>
        <div
          className={`${style.fontWeightBold} ${style.fontLarge} ${style.goldColor} ${style.margin10} ${style.marginBottomOnly}`}
        >
          Dash.
        </div>
        <div
          className={` ${style.fontMedium} ${style.goldColor} ${style.width40}`}
        >
          A personalized dashboard that acts as a portal to your day and helps
          to better manage your time.
        </div>
      </div>
      <div className={`${style.area2}`}>
        <div className={`${style.backgroundStyle}`}>
          <div className={`${style.layer}`}></div>
        </div>
      </div>
      <div className={`${style.area3}`}>
        <div className={`${style.button}`} onClick={onButtonClick}>
          <div
            className={`${style.fontXSmall} ${style.goldColor} ${style.goldColor} ${style.uppercase}  ${style.letterSpacing}`}
          >
            Download Now
          </div>
        </div>
        <div
          className={`${style.fontSmall} ${style.whiteColor} ${style.transparentButton}`}
        >
          made with &lt;3 by{" "}
          <span className={`${style.underline}`} onClick={onHyperlinkCliked}>
            daiviksheth.com
          </span>
        </div>
      </div>
    </div>
  );
};

export default DailyDash;
