import React from "react";
import { Flex } from "reflexbox";
import Header from "./Header";
import About from "./About";
import Work from "./Work";
import ContactUs from "./ContactUs";
import Footer from "./Footer";

const navBar = [
  {
    name: "About Me",
    id: "about",
  },
  {
    name: "Experience",
    id: "work",
  },
  {
    name: "Get In Touch",
    id: "contact",
  },
];

const experience = [
  {
    company: "Dash",
    position: "Product Engineer",
    date: "May 2017 - Present",
    location: "Dayton, NJ",
    description:
      "Designed and developed a personalized dashboard to help keep track of your time and to-dos.",
  },
  {
    company: "Deloitte",
    position: "Senior Software Engineer",
    date: "Oct 2018 - Present",
    location: "Princeton, NJ",
    description:
      "Working on developing performance and user-experience enhancements to an award-winning big data Audit Platorm.",
  },
  {
    company: "Verizon",
    position: "Software Engineer",
    date: "Jun 2017 - Oct 2018",
    location: "Basking Ridge, NJ",
    description:
      "Prototyped, pitched and implemented  enhancements to omni-channel programs such as In-Store Pickup, Offers and  Promotions, same day delivery, and etc.",
  },
  {
    company: "Tumi",
    position: "Software Engineering Intern",
    date: "Oct 2015 - Jun 2018",
    location: "Princeton, NJ",
    description:
      "Colloborated with business and design teams to implement new pages, campaigns and functionalities on Tumi.com.",
  },
];

const Homepage = () => (
  <Flex p={5} flexDirection="column" className={`animated fadeIn`}>
    <Header navBar={navBar} logo="Daivik Sheth" />
    <About />
    <Work experience={experience} />
    <ContactUs />
    <Footer />
  </Flex>
);

export default Homepage;
