import React from "react";
import { Box } from "reflexbox";
import Text from "../Library/Text/Text";
import Hr from "../Library/Hr/Hr";

const About = () => {
  return (
    <Box mt={["20%", "15%", "10%", "7%"]} ml="15%" id="about">
      <Text
        fontSize={["m", "s", "xxs", "xxs"]}
        fontWeight="l"
        textTransform="uppercase"
        letterSpacing="0.1rem"
        mb={["25%", "25%", "10%", "8%"]}
      >
        About Me
        <Hr />
      </Text>
      <Text
        fontSize={["ml", "mm", "xxl", "xxl"]}
        fontWeight="l"
        lineHeight="1"
        width={["95%", "95%", "95%", "95%"]}
        ml={["0%", "10%", "15%", "15%"]}
      >
        Hello! I’m <br></br>{" "}
        <Text display="inline-block" outline>
          Daivik Sheth
        </Text>
        , <br></br> software <br></br> engineer and <br></br> design enthusiast.{" "}
        <br></br> Passionate about <br></br> creating digital <br></br>{" "}
        experiences that <br></br> users love.
      </Text>
    </Box>
  );
};

export default About;
