import React from "react";
import { Flex, Box } from "reflexbox";
import { Link, animateScroll as scroll } from "react-scroll";
import Text from "../Library/Text/Text";
import Hr from "../Library/Hr/Hr";

const Header = ({ navBar, logo }) => {
  const scrollToTop = () => {
    scroll.scrollToTop();
  };

  return (
    <Flex justifyContent="space-between" alignItems="center" width="100%">
      <Text
        fontSize={["m", "s", "xs", "xs"]}
        fontWeight="xxl"
        letterSpacing="0.1rem"
        textTransform="uppercase"
        onClick={scrollToTop}
      >
        {logo}
      </Text>
      <Box mx="auto" />
      {navBar.map((navItem, index) => {
        return (
          <Link
            activeClass="active"
            to={navItem.id}
            spy={true}
            smooth={true}
            offset={-70}
            duration={500}
            key={`navItem-${index}`}
          >
            <Text
              fontSize={["m", "s", "xxs", "xxs"]}
              fontWeight="xl"
              letterSpacing="0.1rem"
              textTransform="uppercase"
              key={index}
              mr={
                !(index === navBar.length - 1)
                  ? ["5px", "20px", "25px", "30px"]
                  : "0px"
              }
              display={["none", "none", "block", "block"]}
              pointer
            >
              {navItem.name}
              <Hr />
            </Text>
          </Link>
        );
      })}
    </Flex>
  );
};

export default Header;
