import React from "react";
import styled, { withTheme } from "styled-components";
import { Box } from "reflexbox";
import Text from "../Text/Text";
import Hr from "../Hr/Hr";

const StyledTile = styled(Box)`
  border: 2px solid;
  border-image: linear-gradient(-225deg, #ffe29f 0%, #ffa99f 48%, #ff719a 100%)
    10;
  max-height: 100%;
`;

const Experience = (work) => {
  return (
    <>
      <Text
        color="title"
        fontSize={["mxxl", "mm", "l", "l"]}
        fontWeight="xl"
        mb="30%"
      >
        {work.company}
      </Text>
      <Text
        fontSize={["mm", "xl", "m", "m"]}
        fontWeight="xl"
        width="15%"
        lineHeight="1.3"
        mb="30%"
      >
        {work.position}
      </Text>
      <Text fontSize={["l", "m", "xs", "xs"]} fontWeight="m">
        {work.date}
        <br></br>
        {work.description}
      </Text>
    </>
  );
};

const Services = (work) => {
  return (
    <>
      <Hr mb="15%"></Hr>
      <Text
        fontSize={["ms", "l", "s", "s"]}
        fontWeight="xl"
        lineHeight="1.3"
        mb="15%"
      >
        {work.position}
      </Text>
      <Text fontSize={["l", "m", "xs", "xs"]} fontWeight="m">
        {work.date}
        <br></br>
        {work.description}
      </Text>
    </>
  );
};

const Tile = ({ type, work, ...extraProps }) => {
  return (
    <StyledTile
      {...extraProps}
      padding={["8vw", "8vw", "2.5vw", "2.5vw"]}
      maxWidth={["60vw", "50vw", "20vw", "20vw"]}
      minWidth={[
        "60vw !important",
        "50vw !important",
        "20vw !important",
        "20vw !important",
      ]}
    >
      {type === "experience" ? (
        <Experience {...work} />
      ) : (
        <Services {...work} />
      )}
    </StyledTile>
  );
};

export default withTheme(Tile);
